const body = $input.item.json.snippet || $input.item.json.body || '';

// Extract Greek/Latin postal code (5 digits)
const tkMatch = body.match(/\b(\d{5})\b/);
const tk = tkMatch ? tkMatch[1] : null;

// Extract address (heuristic: look for street patterns)
const addressMatch = body.match(/([Α-Ωα-ω\w]+\.?\s+\d+[\s,]+[Α-Ωα-ω\w\s]+)/u);
const address = addressMatch ? addressMatch[0].trim() : body.substring(0, 200);

return [{
  json: {
    ...$input.item.json,
    extracted_tk: tk,
    extracted_address: address,
    deal_id: $node["Pipedrive Trigger"].json.id
  }
}];
